// Parse AI Agent output to extract structured ideas
const rawOutput = $json.output ?? $json.result ?? $json.response ?? $json;
let parsed = null;

// Try to parse JSON from string output
if (typeof rawOutput === 'string') {
  try {
    // Extract JSON from markdown code blocks if present
    const jsonMatch = rawOutput.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || rawOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
    } else {
      parsed = JSON.parse(rawOutput);
    }
  } catch (e) {
    // If parsing fails, try to extract ideas from text
    console.warn('Failed to parse JSON from AI output:', e);
    parsed = { ideas: [], userIdea: rawOutput, totalIdeas: 0 };
  }
} else if (typeof rawOutput === 'object') {
  parsed = rawOutput;
}

const userIdea = parsed?.userIdea || $('Get Run').item.json.user_idea || $('When Called').item.json.userInput || '';

// Ensure each idea has required fields

return {
  json: {
    ideas: rawOutput,
    userIdea: userIdea,
    totalIdeas: rawOutput.length,

  }
};

// Prepare batch video data from parsed ideas
const parsedOutput = $json;
const ideas = parsedOutput.ideas ?? [];
const runData = $('Get Run').item?.json ?? {};
const runId = $('When Called').item.json.runId;
const projectId = runData.project_id || runData.projectId || 'aismr';
const userIdea = parsedOutput.userIdea || runData.user_idea || $('When Called').item.json.userInput || '';
const startedAt = new Date().toISOString();

// Format each idea for batch creation
const batchData = ideas.map((idea) => ({
  runId: runId,
  projectId: projectId,
  idea: idea.ideaTitle || idea.idea || '',
  userIdea: userIdea,
  vibe: idea.vibe || null,
  status: 'idea_gen',
  prompt: null,
  startedAt: startedAt,
  metadata: { source: 'idea-generator' }
}));

return [{
  json: {
    batchData,
    runId,
    projectId,
    userIdea,
    totalIdeas: batchData.length
  }
}];

const payload = $json?.workflowRun ?? $json?.data?.workflowRun ?? null;
if (!payload) {
  throw new Error('Workflow run payload missing from API response.');
}

const metadata = {};
if (payload.input && typeof payload.input === 'object') {
  if (payload.input.metadata && typeof payload.input.metadata === 'object') {
    Object.assign(metadata, payload.input.metadata);
  }
  if (payload.input.turn && typeof payload.input.turn === 'object' && payload.input.turn.metadata && typeof payload.input.turn.metadata === 'object') {
    Object.assign(metadata, payload.input.turn.metadata);
  }
  if (payload.input.projectSlug && typeof payload.input.projectSlug === 'string' && !metadata.projectSlug) {
    metadata.projectSlug = payload.input.projectSlug;
  }
}
if (!metadata.projectSlug && typeof payload.projectId === 'string') {
  metadata.projectSlug = payload.projectId;
}

const normalized = {
  ...payload,
  run_id: payload.id,
  project_id: payload.projectId ?? null,
  projectId: payload.projectId ?? null,
  session_id: payload.sessionId ?? null,
  sessionId: payload.sessionId ?? null,
  user_idea:
    (payload.input?.userIdea ??
      payload.input?.user_idea ??
      metadata.userIdea ??
      '') || '',
  input: payload.input ?? {},
  metadata,
};

return [{ json: normalized }];

// Aggregate all ideas from batch creation response or parsed output
const ideas = [];
const runData = $('Get Run').item?.json ?? {};
const workflowRunId = runData.run_id || runData.id || $('When Called').item.json.runId;
const projectId = runData.project_id || runData.projectId || 'aismr';

// Check if batch creation succeeded
const batchResponse = $('Create Batch Videos').item?.json;
const parsedOutput = $('Parse Ideas Output').item?.json;

if (batchResponse?.data?.videos && Array.isArray(batchResponse.data.videos)) {
  // Use videos from batch creation response
  ideas.push(...batchResponse.data.videos.map((v) => ({
    ideaTitle: v.idea,
    idea: v.idea,
    vibe: v.vibe,
    ideaId: v.id
  })));
} else if (parsedOutput && Array.isArray(parsedOutput.ideas)) {
  // Fallback: use ideas from parsed output
  ideas.push(...parsedOutput.ideas);
} else {
  // Last resort: collect from input items
  for (const item of $input.all()) {
    if (item.json.idea) {
      ideas.push({
        idea: item.json.idea,
        vibe: item.json.vibe,
        ideaId: item.json.run_id || item.json.id || item.json.ideaId,
      });
    }
  }
}

const userIdea = parsedOutput?.userIdea || runData.user_idea || runData.metadata?.userIdea || runData.input?.userIdea || runData.input?.user_idea || $('When Called').item.json.userInput || '';

return [{
  json: {
    workflowRunId,
    projectId,
    ideas,
    userIdea: userIdea,
    totalIdeas: ideas.length,
  }
}];

parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "required": [
      "ideaTitle",
      "vibe",
      "uniquenessCheck"
    ],
    "properties": {
      "ideaTitle": {
        "type": "string",
        "description": "Exactly 2 words following pattern: [SURREAL MODIFIER] [OBJECT] (e.g., 'velvet puppy', 'void puppy', 'water puppy', 'sunrise puppy')",
        "pattern": "^[a-zA-Z]+ [a-zA-Z]+$"
      },
      "vibe": {
        "type": "string",
        "description": "2-3 sentences describing atmosphere and mood for screenwriter"
      },
      "uniquenessCheck": {
        "type": "object",
        "properties": {
          "exists": {
            "type": "boolean"
          },
          "matchedVideos": {
            "type": "array",
            "items": {
              "type": "object"
            }
          },
          "confidence": {
            "type": "string",
            "enum": [
              "exact",
              "fuzzy",
              "none"
            ]
          }
        }
      }
    }
  }
}
